#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int v[100005],v1[100005],v2[100005],p[100005],p1[100005],p2[100005],mx;
int dp[100005];
signed main(void){
	int n,m;
	cin>>n>>m;
	for(int i=1;i<=m;++i){
		int a,b,c;cin>>a>>b>>c;
		if(!c)v[i]=a,p[i]=b;
		else{
			if(v1[c]==0)v1[c]=a,p1[c]=b;
			else v2[c]=a,p2[c]=b;
		}
	}
	for(int i=1;i<=m;++i){
		for(int j=n;j>=v[i];--j){
			dp[j]=max(dp[j],dp[j-v[i]]+v[i]*p[i]);
			if(j>=v[i]+v1[i])dp[j]=max(dp[j],dp[j-v[i]-v1[i]]+v[i]*p[i]+v1[i]*p1[i]);//DP选最大值（分类讨论3种情况）

			if(j>=v[i]+v2[i])dp[j]=max(dp[j],dp[j-v[i]-v2[i]]+v[i]*p[i]+v2[i]*p2[i]);
			if(j>=v[i]+v1[i]+v2[i])dp[j]=max(dp[j],dp[j-v[i]-v1[i]-v2[i]]+v[i]*p[i]+v1[i]*p1[i]+v2[i]*p2[i]);
			mx=max(mx,dp[j]);
		}
	}
	cout<<dp[n];
	return false;
}
